insert into public.subthemes(theme_id, slug, name, description, priority_rank, is_active)
select t.id, ss.theme_slug || '__' || ss.sub_slug, ss.sub_name, ss.issue, ss.priority_rank, true
from subtheme_seed ss
join public.themes t on t.slug = ss.theme_slug;

